// historyTimeAgo returns a human-readable relative time string using i18n.
func historyTimeAgo(ctx context.Context, ts time.Time) string {
	dur := time.Since(ts)
	switch {
	case dur < time.Minute:
		return t(ctx, "time.just_now")
	case dur < time.Hour:
		return tn(ctx, "time.history.minutes_ago", int(dur.Minutes()))
	case dur < 24*time.Hour:
		return tn(ctx, "time.history.hours_ago", int(dur.Hours()))
	case dur < 7*24*time.Hour:
		return tn(ctx, "time.history.days_ago", int(dur.Hours()/24))
	default:
		layout := t(ctx, "time.history.date_format")
		if layout == "" || layout == "time.history.date_format" {
			layout = "Jan 2, 2006"
		}
		return ts.Format(layout)
	}
}

// historySourceLabel converts a source string to a human-readable label.
func historySourceLabel(ctx context.Context, source string) string {
	switch {
	case source == "manual":
		return t(ctx, "history.source.manual")
	case source == "scan":
		return t(ctx, "history.source.scan")
	case source == "import":
		return t(ctx, "history.source.import")
	case source == "revert":
		return t(ctx, "history.source.revert")
	case strings.HasPrefix(source, "provider:"):
		name := strings.TrimPrefix(source, "provider:")
		if name == "" {
			return t(ctx, "history.source.provider")
		}
		// Provider names are brand names -- not translated.
		return tf(ctx, "history.source.provider_named", name)
	case strings.HasPrefix(source, "rule:"):
		ruleID := strings.TrimPrefix(source, "rule:")
		if ruleID == "" {
			return t(ctx, "history.source.rule")
		}
		return tf(ctx, "history.source.rule_named", ruleID)
	default:
		return source
	}
}

// historySourceBadgeClass returns Tailwind classes for the source badge.
// Revert entries get a distinct amber color to stand out in the timeline.
func historySourceBadgeClass(source string) string {
	if source == "revert" {
		return "bg-amber-100 dark:bg-amber-900/40 text-amber-700 dark:text-amber-300"
	}
	return "bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300"
}

// historyFieldLabel converts a database field name to a human-readable label.
// It delegates to fieldLabel for the actual label mapping.
func historyFieldLabel(ctx context.Context, field string) string {
	return fieldLabel(ctx, field)
}

// HistoryFieldLabel is the exported wrapper around the shared field-label
// vocabulary so the next/ channel's activity rail can render field names with
// the same localized labels the stable history view uses, without duplicating
// the lookup table.
func HistoryFieldLabel(ctx context.Context, field string) string {
	return fieldLabel(ctx, field)
}

// historyTruncate trims a string to at most maxLen visible characters, adding
// an ellipsis if truncation occurs. Uses rune-based length to handle multi-byte
// Unicode correctly.
func historyTruncate(s string, maxLen int) string {
	// Normalize newlines for display.
	s = strings.ReplaceAll(s, "\n", " ")
	s = strings.ReplaceAll(s, "\r", "")
	runes := []rune(s)
	if len(runes) <= maxLen {
		return s
	}
	return string(runes[:maxLen]) + "..."
}

